// Combine lead data with contact info for outreach generation
const lead = $('Fetch Lead Data').first().json.fields;
const contacts = ($('Fetch Contacts').first().json.records || []).map(r => r.fields);
const channel = $('Webhook: Generate Outreach').first().json.channel || 'all';

let qualification = {};
try {
  qualification = JSON.parse(lead['Qualification JSON'] || '{}');
} catch (e) {
  qualification = {};
}

// Pick best contact by confidence score
const bestContact = contacts.sort((a, b) => (b['Confidence'] || 0) - (a['Confidence'] || 0))[0] || {
  'Contact Name': '[Contact Name]',
  'Title': '[Title]',
  'Email': '[email]'
};

return [{
  json: {
    lead_id: $('Webhook: Generate Outreach').first().json.lead_id,
    channel: channel,
    contact: {
      name: bestContact['Contact Name'] || '[Contact Name]',
      first_name: (bestContact['Contact Name'] || '').split(' ')[0] || '[First Name]',
      title: bestContact['Title'] || '[Title]',
      email: bestContact['Email'] || '[email]',
      company: bestContact['Company'] || lead['Company Name']
    },
    qualification: {
      retailer_name: lead['Company Name'],
      website: lead['Website'],
      lead_score: lead['Lead Score'],
      recommendation: lead['Recommendation'],
      pitch_angle: qualification.lead_score?.pitch_angle || '',
      shared_brands: (qualification.brand_overlap?.shared_brands || []).map(b => b.brand || b),
      brands_to_pitch: (qualification.brand_overlap?.you_carry_they_dont || []).map(b => b.brand || b),
      store_type: qualification.overview?.store_type || '',
      brand_positioning: qualification.overview?.brand_positioning || ''
    }
  }
}];

